VALUES
  ('social-worker-moex-07960', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利組織或機構為了財務原因大都需要作募款的工作，惟一般社會大眾不願意捐款的原因，下列何 者錯誤？', '["個人的特質與情境問題", "非營利組織溝通的問題", "政府的誘因問題", "非營利組織的社會形象問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07961', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '行銷概念的發展從生產觀念、產品觀念、銷售觀念、行銷觀念到最近的社會行銷觀念。下列對社會行銷 特性的描述何者不正確？', '["社會行銷強調企業組織存在不只為滿足顧客需求及組織目標", "社會行銷強調要為個人及社會盡份心力", "行銷人員在擬定行銷策略時必須將未參與交換或交易的社會大眾福祉列入考量", "社會行銷追求公司利潤、顧客滿足及企業福祉的平衡"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07962', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '傳統而言志工一直是社會福利機構或非營利組織的主要人力資源，兩者亦維繫著互助互利關係。惟志工 與全職工作人員有所差異，因此在管理上要注意的事項下列何者不正確？', '["志工與一般員工工作動機不同，因此他們不要求金錢報償，而是要求合理勞務及工作的自主權與決策權", "由於機構的董事或主要贊助者本身亦都為志工，他們卻以投入奉獻為主，所以會用自己的標準看待功 績制度", "非營利組織的志工專業人員比一般營利或公務機關更看重專業價值的自我肯定，要求更大自主及參與 決策，並容易形成小圈圈造成管理上的困擾", "志工的管理應與一般員工一樣對待並不需要特別留意其差異性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07963', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於優勢督導觀點（strength-based approach to supervision）的描述那項不正確？', '["拒絕接受人應該依其缺點、問題或限制做專業判斷的認定", "應該鼓勵實務工作者與人們共同致力於找出過去優勢來源及其生活中的復原力", "優勢觀點的督導主要是以被動的或危機取向做工作基礎", "督導應著重於促進專業發展和品質的提升並從成功中學習"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07964', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於服務方案的評值其意義的歸納內容，下列何者錯誤？', '["方案評值是對方案之實施從事包括質化與量化的追蹤評量過程", "方案評值是針對方案努力、效益、效率和適當性作合理的判斷", "方案評值是建立在一般性的資料蒐集和分析上", "方案評值是設計來使用於方案管理、外部的責信以及外來的規劃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07965', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關探討領導的理論除了特質論、行為論外，另一則是權變理論，而在權變理論中Fred Fiedler的權變模 式是其一，他主張有效的團體績效端視領導者與其部屬的互動型態，以及所處的情境與領導者影響力的 適切配合。而Fiedler認為影響領導者效能的情境因素有三種變數，請問下列何者錯誤？', '["領導者與部屬之間的關係", "員工的成熟度", "任務結構", "職位的權力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07966', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '面對管理的外在環境愈趨向混沌和複雜，新世代的管理策略必將作不同的調整和改變，下列的作法何者 錯誤？', '["應將組織當成一個活的系統，可以調整改變及自我組織", "最好能透過想像和隱喻來理解組織內所進行的所有活動", "一切決策的行為都是理性且所有改變皆可以預期", "管理變成為一種創造性活動能應付不確定性與弔詭性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07967', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '成功的人力資源規劃取決於三個要件，下列何者不是要件之一？', '["完善的人力資源法律", "有效的組織決策", "員工需求的面向", "工作分析"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07968', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在競爭的環境下社會福利機構或非營利組織都需要訂定一個好的策略以為應對，下列的描述何者不是好 的策略項目？', '["策略的目的在界定組織的生存發展空間與範圍", "策略必須為組織挑定發展重點的優先順序", "一個好策略要能與外在環境維持既平衡又不平衡的關係", "一個好策略要維持長期追求利潤的優勢"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07969', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '面對社會福利機構及非營利組織皆有因不同原因而導致員工的離職情況，雖然在社福機構及非營利組織 大都強調溫暖接納和共聚理想，但面對不可避免的事情發生，要能堅守三大原則使整個離職事件能圓滿 處理，下列何者不屬這三項原則？', '["公平", "包容", "誠實", "合理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
